function transform(node) {
  if (Array.isArray(node)) return node.map(transform)
  if (node && typeof node === "object") {
    for (const k of Object.keys(node)) {
      if (k === "mr_kowalski") {
        node["John Ronald Kowalski"] = transform(node[k])
        delete node[k]
      } else {
        node[k] = transform(node[k])
      }
    }
  }
  return node
}

