const path = "~/contacts.yaml"
const text = await space.api.fileRead(path, "utf8")
const data = space.utils.yaml.parse(text)

function updateMrKowalski(node) {
  if (!node || typeof node !== "object") return false

  let changed = false

  if (Array.isArray(node)) {
    for (const item of node) changed = updateMrKowalski(item) || changed
    return changed
  }

  for (const [key, value] of Object.entries(node)) {
    if (key === "mr_kowalski") {
      node[key] = "John Ronald Kowalski"
      changed = true
    } else if (value && typeof value === "object") {
      changed = updateMrKowalski(value) || changed
    }
  }

  return changed
}

const changed = updateMrKowalski(data)
if (!changed) throw new Error("mr_kowalski not found in contacts.yaml")

