const src = await space.current.readWidget("snake-game")
const text = typeof src === "string" ? src : JSON.stringify(src)

const updated = text.replace(
  /(\bsize\b[^;\n]*?)(\/\s*([\d.]+)|\*\s*([\d.]+))?/g,
  (m) => m
)

// Fallback patch: try to enforce a minimum tail scale in likely snake style code.
let patched = text
patched = patched.replace(/tail.*?scale\s*[:=]\s*([0-9.]+)/si, (m, n) => m.replace(n, "0.6"))
patched = patched.replace(/(\bMath\.max\s*\(\s*)([0-9.]+)(\s*,\s*[^)]+\))/g, (m, a, b, c) => `${a}0.6${c}`)

return await space.current.patchWidget("snake-game", { edits: [{ op: "replace", path: "/", value: patched }] })

